// TG-138: Aggregate this week's metrics from all Supabase tables
const supabaseUrl = $vars.TG_SUPABASE_URL ? `${$vars.TG_SUPABASE_URL}/rest/v1` : 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = $vars.TG_SUPABASE_ANON_KEY || '';
const serviceKey = $vars.TG_SUPABASE_SERVICE_KEY || supabaseKey;
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${serviceKey}`
};

const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();

async function safeFetch(url) {
  try {
    const r = await this.helpers.httpRequest({ method: 'GET', url, headers: supabaseHeaders });
    return Array.isArray(r) ? r : [];
  } catch (e) { return []; }
}

// 1. Leads this week
const leads = await safeFetch.call(this,
  `${supabaseUrl}/leads?created_at=gte.${weekAgo}&select=id,first_name,last_name,name,source,status,lead_tier,created_at`);

// 2. Jobs this week from jobber_email_events
const jobs = await safeFetch.call(this,
  `${supabaseUrl}/jobber_email_events?event_date=gte.${weekAgo}&select=id,event_type,customer_name`);

// 3. Google reviews this week
const reviews = await safeFetch.call(this,
  `${supabaseUrl}/google_reviews?created_at=gte.${weekAgo}&select=id,author_name,rating,text`);

// 4. All reviews for overall stats
const allReviews = await safeFetch.call(this,
  `${supabaseUrl}/google_reviews?select=id,rating`);

// 5. Blog posts published this week
const blogPosts = await safeFetch.call(this,
  `${supabaseUrl}/blog_posts?published_at=gte.${weekAgo}&status=eq.published&select=id,title,slug`);

// 6. GBP posts this week
const gbpPosts = await safeFetch.call(this,
  `${supabaseUrl}/gbp_posts?published_at=gte.${weekAgo}&select=id,post_type,topic`);

// 7. Social posts this week
const socialPosts = await safeFetch.call(this,
  `${supabaseUrl}/social_posts?published_at=gte.${weekAgo}&status=eq.published&select=id,platforms,pillar`);

// 8. Review requests this week
const reviewRequests = await safeFetch.call(this,
  `${supabaseUrl}/review_requests?created_at=gte.${weekAgo}&select=id,status`);

// 9. n8n executions this week
let executions = { total: 0, errors: 0, errorWorkflows: [] };
try {
  const n8nKey = $vars.TG_N8N_API_KEY || 'N8N_API_KEY_PLACEHOLDER';
  const allExecs = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://tgyardcare.app.n8n.cloud/api/v1/executions?limit=250',
    headers: { 'X-N8N-API-KEY': n8nKey }
  });
  const data = (allExecs && allExecs.data) ? allExecs.data : (Array.isArray(allExecs) ? allExecs : []);
  const weekData = data.filter(e => {
    try { return new Date(e.startedAt || e.createdAt) >= new Date(weekAgo); }
    catch(ex) { return false; }
  });
  executions.total = weekData.length;
  const errorExecs = weekData.filter(e => e.status === 'error');
  executions.errors = errorExecs.length;
  // Most errored workflows
  const wfErrors = {};
  for (const e of errorExecs) {
    const name = e.workflowData?.name || e.workflowId || 'unknown';
    wfErrors[name] = (wfErrors[name] || 0) + 1;
  }
  executions.errorWorkflows = Object.entries(wfErrors).sort((a, b) => b[1] - a[1]).slice(0, 3);
} catch (e) { /* defaults */ }

return [{
  json: {
    leads, jobs, reviews, allReviews, blogPosts, gbpPosts, socialPosts,
    reviewRequests, executions, weekAgo
  }
}];

// TG-138: Fetch previous week's metrics and calculate trends
const supabaseUrl = $vars.TG_SUPABASE_URL ? `${$vars.TG_SUPABASE_URL}/rest/v1` : 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = $vars.TG_SUPABASE_ANON_KEY || '';
const serviceKey = $vars.TG_SUPABASE_SERVICE_KEY || supabaseKey;
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${serviceKey}`
};

const current = $input.first().json;
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();
const twoWeeksAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000).toISOString();

async function prevCount(table, dateCol, extraFilter) {
  try {
    const filter = extraFilter ? `&${extraFilter}` : '';
    const r = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}/${table}?${dateCol}=gte.${twoWeeksAgo}&${dateCol}=lt.${weekAgo}&select=id${filter}`,
      headers: supabaseHeaders
    });
    return Array.isArray(r) ? r.length : 0;
  } catch (e) { return 0; }
}

const prevLeads = await prevCount.call(this, 'leads', 'created_at');
const prevJobs = await prevCount.call(this, 'jobber_email_events', 'event_date');
const prevReviews = await prevCount.call(this, 'google_reviews', 'created_at');
const prevBlogPosts = await prevCount.call(this, 'blog_posts', 'published_at', 'status=eq.published');
const prevSocialPosts = await prevCount.call(this, 'social_posts', 'published_at', 'status=eq.published');

function trend(cur, prev) {
  if (prev === 0) return cur > 0 ? { pct: '+100%', arrow: '\u2b06\ufe0f' } : { pct: '0%', arrow: '\u27a1\ufe0f' };
  const change = ((cur - prev) / prev * 100).toFixed(0);
  const arrow = change > 0 ? '\u2b06\ufe0f' : change < 0 ? '\u2b07\ufe0f' : '\u27a1\ufe0f';
  return { pct: `${change > 0 ? '+' : ''}${change}%`, arrow };
}

return [{
  json: {
    ...current,
    trends: {
      leads: trend(current.leads.length, prevLeads),
      jobs: trend(current.jobs.length, prevJobs),
      reviews: trend(current.reviews.length, prevReviews),
      blogPosts: trend(current.blogPosts.length, prevBlogPosts),
      socialPosts: trend(current.socialPosts.length, prevSocialPosts)
    },
    prev: { leads: prevLeads, jobs: prevJobs, reviews: prevReviews, blogPosts: prevBlogPosts, socialPosts: prevSocialPosts }
  }
}];

// TG-138: Build formatted weekly report for Telegram
const d = $input.first().json;

const now = new Date();
const weekStart = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000)
  .toLocaleDateString('en-US', { timeZone: 'America/Chicago', month: 'short', day: 'numeric' });
const weekEnd = now.toLocaleDateString('en-US', { timeZone: 'America/Chicago', month: 'short', day: 'numeric', year: 'numeric' });

const leads = d.leads || [];
const jobs = d.jobs || [];
const reviews = d.reviews || [];
const allReviews = d.allReviews || [];
const blogPosts = d.blogPosts || [];
const gbpPosts = d.gbpPosts || [];
const socialPosts = d.socialPosts || [];
const reviewRequests = d.reviewRequests || [];
const executions = d.executions || { total: 0, errors: 0, errorWorkflows: [] };
const trends = d.trends || {};
const prev = d.prev || {};

// Lead sources breakdown
const leadSources = {};
for (const l of leads) {
  const src = (l.source || 'unknown').toLowerCase();
  leadSources[src] = (leadSources[src] || 0) + 1;
}
const sourceLines = Object.entries(leadSources)
  .sort((a, b) => b[1] - a[1])
  .map(([src, count]) => `  ${src}: ${count}`).join('\n') || '  None';

// Lead conversion
const converted = leads.filter(l => l.lead_tier === 'converted' || l.status === 'converted').length;
const convRate = leads.length > 0 ? ((converted / leads.length) * 100).toFixed(0) : '0';
const hotLeads = leads.filter(l => l.lead_tier === 'hot').length;

// Job event breakdown
const jobTypes = {};
for (const j of jobs) {
  const t = j.event_type || 'other';
  jobTypes[t] = (jobTypes[t] || 0) + 1;
}

// Review stats
let avgRating = '0';
if (allReviews.length > 0) {
  avgRating = (allReviews.reduce((s, r) => s + (r.rating || 0), 0) / allReviews.length).toFixed(1);
}
const reviewReqSent = reviewRequests.length;
const reviewReqCompleted = reviewRequests.filter(r => r.status === 'completed' || r.status === 'reviewed').length;
const responseRate = reviewReqSent > 0 ? ((reviewReqCompleted / reviewReqSent) * 100).toFixed(0) : '0';

// System health
const successRate = executions.total > 0
  ? ((1 - executions.errors / executions.total) * 100).toFixed(1)
  : '100.0';

// Top win / top issue logic
let topWin = 'Steady operations';
let topIssue = 'All systems nominal';

if (leads.length > (prev.leads || 0) && (trends.leads?.pct || '').startsWith('+')) {
  topWin = `Lead volume up ${trends.leads.pct} (${leads.length} vs ${prev.leads})`;
} else if (reviews.length > 0) {
  topWin = `${reviews.length} new reviews this week`;
} else if (blogPosts.length > 0) {
  topWin = `${blogPosts.length} blog posts published`;
}

if (executions.errors > 5) {
  topIssue = `${executions.errors} workflow errors need attention`;
} else if (leads.length === 0) {
  topIssue = 'Zero new leads this week';
} else if (leads.length < (prev.leads || 0)) {
  topIssue = `Lead volume down ${trends.leads.pct}`;
}

const t = trends;
const lines = [
  `\ud83d\udcca TOTALGUARD WEEKLY REPORT`,
  `${weekStart} \u2014 ${weekEnd}`,
  `\u2501`.repeat(28),
  '',
  `\ud83d\udce5 LEAD PIPELINE`,
  `New leads: ${leads.length} ${t.leads?.arrow || ''} ${t.leads?.pct || ''}`,
  `Hot leads: ${hotLeads}`,
  `Converted: ${converted} (${convRate}%)`,
  `By source:`,
  sourceLines,
  '',
  `\ud83d\udee0\ufe0f OPERATIONS`,
  `Total events: ${jobs.length} ${t.jobs?.arrow || ''} ${t.jobs?.pct || ''}`,
  ...(Object.entries(jobTypes).map(([type, count]) => `  ${type}: ${count}`)),
  '',
  `\u2b50 REPUTATION`,
  `New reviews: ${reviews.length} ${t.reviews?.arrow || ''} ${t.reviews?.pct || ''}`,
  `Avg rating: ${avgRating}/5 (${allReviews.length} total)`,
  reviewReqSent > 0 ? `Review requests: ${reviewReqSent} sent, ${reviewReqCompleted} completed (${responseRate}%)` : '',
  '',
  `\ud83d\udcdd CONTENT & SEO`,
  `Blog posts: ${blogPosts.length} ${t.blogPosts?.arrow || ''} ${t.blogPosts?.pct || ''}`,
  `GBP posts: ${gbpPosts.length}`,
  `Social posts: ${socialPosts.length} ${t.socialPosts?.arrow || ''} ${t.socialPosts?.pct || ''}`,
  '',
  `\u2699\ufe0f SYSTEM HEALTH`,
  `Executions: ${executions.total}`,
  `Errors: ${executions.errors} (${successRate}% success)`,
  ...(executions.errorWorkflows || []).map(([name, count]) => `  \u274c ${name}: ${count} errors`),
  '',
  `\u2501`.repeat(28),
  '',
  `\ud83c\udfc6 TOP WIN: ${topWin}`,
  `\u26a0\ufe0f TOP ISSUE: ${topIssue}`,
  '',
  `Have a great week! \ud83d\ude80`
];

return [{ json: { message: lines.filter(l => l !== undefined && l !== '').join('\n') } }];
